-- labs 테이블 — data/labs.json 의 supabase 화 (현상소 admin 편집용)
-- public 은 SELECT, editor 만 INSERT/UPDATE/DELETE. films 패턴과 동일.

create table if not exists public.labs (
  id          uuid primary key default gen_random_uuid(),
  name        text not null,
  region      text,
  address     text,
  lat         double precision,
  lng         double precision,
  scan_res    text,
  features    text,
  url         text,
  prices      jsonb not null default '{}'::jsonb,
  is_hidden   boolean not null default false,
  sort_order  int,
  created_at  timestamptz not null default now(),
  updated_at  timestamptz not null default now()
);

create index if not exists labs_region_idx on public.labs (region);
create index if not exists labs_sort_idx   on public.labs (sort_order);

create or replace function public._labs_touch_updated_at()
returns trigger language plpgsql as $$
begin new.updated_at := now(); return new; end $$;

drop trigger if exists labs_touch_updated_at on public.labs;
create trigger labs_touch_updated_at
  before update on public.labs
  for each row execute function public._labs_touch_updated_at();

alter table public.labs enable row level security;

drop policy if exists "labs_public_select" on public.labs;
create policy "labs_public_select" on public.labs for select using (true);

drop policy if exists "labs_editor_insert" on public.labs;
create policy "labs_editor_insert" on public.labs for insert to authenticated
  with check (exists (select 1 from public.profiles where user_id = auth.uid() and is_editor = true));

drop policy if exists "labs_editor_update" on public.labs;
create policy "labs_editor_update" on public.labs for update to authenticated
  using (exists (select 1 from public.profiles where user_id = auth.uid() and is_editor = true))
  with check (exists (select 1 from public.profiles where user_id = auth.uid() and is_editor = true));

drop policy if exists "labs_editor_delete" on public.labs;
create policy "labs_editor_delete" on public.labs for delete to authenticated
  using (exists (select 1 from public.profiles where user_id = auth.uid() and is_editor = true));

